import re

# Read all ST files
import glob
st_files = {}
for f in glob.glob('ST_*.st'):
    with open(f, 'r', encoding='utf-8') as fh:
        st_files[f] = fh.read()

# Get all M used
m_used = set()
for fname, content in st_files.items():
    for m in re.findall(r'\bM([0-9A-Fa-f]{5})\b', content):
        m_used.add('M' + m.upper())
    for m in re.findall(r'\bM([0-9A-Fa-f]{4})\b', content):
        var = 'M' + m.upper()
        for line in content.split('\n'):
            if var in line or ('M' + m) in line:
                if 'DECO' not in line:
                    m_used.add(var)
                    break

# Read GVL
with open('GVL_INTERNAL.st', 'r', encoding='utf-8') as f:
    gvl_content = f.read()

m_declared = set()
for m in re.findall(r'\b(M[0-9A-Fa-f]{4,5})\b', gvl_content):
    m_declared.add(m.upper())

m_missing = sorted(m_used - m_declared)

# For each missing var, find which file uses it and get context
var_context = {}
for var in m_missing:
    for fname, content in st_files.items():
        for line in content.split('\n'):
            if re.search(r'\b' + var + r'\b', line):
                # Get file short name
                short = fname.replace('ST_', '').replace('.st', '')
                if var not in var_context:
                    var_context[var] = (short, line.strip()[:80])
                break

# Print all missing with context
